import time
import uuid

class ATMNetwork:
    def __init__(self):
        self.atms = {}
        self.lock = threading.Lock()
        self.fraud_detection = FraudDetection()

    def add_atm(self, atm_id, atm):
        with self.lock:
            self.atms[atm_id] = atm

    def remove_atm(self, atm_id):
        with self.lock:
            del self.atms[atm_id]

    def perform_transaction(self, atm_id, transaction):
        with self.lock:
            if atm_id not in self.atms:
                return False
            atm = self.atms[atm_id]
            if not self.fraud_detection.check_fraud(transaction):
                return False
            if not atm.process_transaction(transaction):
                return False
            return True

class ATM:
    def __init__(self):
        self.lock = threading.Lock()
        self.balance = 0

    def process_transaction(self, transaction):
        with self.lock:
            if transaction.amount > self.balance:
                return False
            self.balance -= transaction.amount
            return True

