        self.timestamp = time.time()

class FraudDetection:
    def __init__(self):
        self.recent_transactions = {}

    def check_fraud(self, transaction):
        with threading.Lock():
            if transaction.id in self.recent_transactions:
                return False
            self.recent_transactions[transaction.id] = transaction
            return True

