        while True:
            time.sleep(1)
            with self.atm_network.lock:
                for transaction in self.atm_network.transaction_log:
                    atm_id, account_number, amount = transaction
                    if self.is_transaction_secure(atm_id, account_number, amount):
                        self.atm_network.transaction_log.remove(transaction)
