        with self.lock:
            if is_deposit:
                self.atm_balances[atm_id] += amount
            else:
                if self.atm_balances[atm_id] >= amount:
                    self.atm_balances[atm_id] -= amount
                else:
                    return False
            self.transaction_log.append((atm_id, amount, is_deposit))
            return True

    def detect_fraud(self):
        with self.lock:
            balances = self.atm_balances[:]
            for i in range(self.num_atms):
                for j in range(i+1, self.num_atms):
                    if abs(balances[i] - balances[j]) > 100:
                        return True
            return False

