import threading
import queue

class ATMNetwork:
    def __init__(self, num_atms):
        self.num_atms = num_atms
        self.atm_queues = [queue.Queue() for _ in range(num_atms)]
        self.transaction_log = []
        self.lock = threading.Lock()

    def process_transaction(self, atm_id, transaction):
        with self.lock:
            if transaction['type'] == 'withdrawal':
                if transaction['amount'] <= self.atm_queues[atm_id].queue[0]['balance']:
                    self.atm_queues[atm_id].queue[0]['balance'] -= transaction['amount']
                    self.transaction_log.append(transaction)
                    return True
                else:
                    return False
            elif transaction['type'] == 'deposit':
                self.atm_queues[atm_id].queue[0]['balance'] += transaction['amount']
                self.transaction_log.append(transaction)
                return True

    def run_atm(self, atm_id):
        while True:
            transaction = self.atm_queues[atm_id].get()
            if not self.process_transaction(atm_id, transaction):
                self.atm_queues[atm_id].put(transaction)
            self.atm_queues[atm_id].task_done()

    def add_transaction(self, atm_id, transaction):
        self.atm_queues[atm_id].put(transaction)

    def start(self):
        for i in range(self.num_atms):
            t = threading.Thread(target=self.run_atm, args=(i,))
            t.daemon = True
            t.start()

