        for i in range(len(self.transactions) - 1):
            for j in range(i + 1, len(self.transactions)):
                if self.transactions[i]['card_number'] == self.transactions[j]['card_number'] and \
                   self.transactions[i]['type'] == self.transactions[j]['type'] and \
                   abs((datetime.datetime.strptime(self.transactions[i]['timestamp'], '%Y-%m-%d %H:%M:%S') -
